// Phase 12d — workflow JSON dry-run flags (no $env; staging n8n blocks env in expressions)
const inbound = $input.first().json;
return [{
  json: {
    ...inbound,
    dry_run: true,
    live_send_enabled: false
  }
}];

// Phase 12f — parse inbound guest booking payload for /staff/bot/booking-dry-run
const body = $input.first().json.body || $input.first().json;

const phone         = String(body.guest_phone || body.phone || body.from || '+34999000000').trim();
const guestName     = String(body.guest_name || body.name || '').trim() || null;
const email         = String(body.email || '').trim() || null;
const checkIn       = String(body.check_in || '').trim() || null;
const checkOut      = String(body.check_out || '').trim() || null;
const guestCount    = parseInt(body.guest_count || body.adults || body.guests || '1', 10) || 1;
const packageCode   = String(body.package_code || 'malibu').trim();
const roomType      = String(body.room_type || body.room_preference || 'shared').trim();
const paymentChoice = String(body.payment_choice || 'deposit').trim();
const addOns        = Array.isArray(body.add_ons) ? body.add_ons : [];
const language      = String(body.language || 'en').trim();
const clientSlug    = String(body.client_slug || 'wolfhouse-somo').trim();
const messageText   = body.message_text != null ? String(body.message_text) : null;
const conversationId = body.conversation_id != null ? String(body.conversation_id).trim() : null;
const bookingCode   = body.booking_code != null ? String(body.booking_code).trim() : null;
const addonRequest  = body.addon_request && typeof body.addon_request === 'object' ? body.addon_request : null;

return [{
  json: {
    client_slug: clientSlug,
    phone,
    guest_phone: phone,
    guest_name: guestName,
    email,
    check_in: checkIn,
    check_out: checkOut,
    guest_count: guestCount,
    package_code: packageCode,
    room_type: roomType,
    payment_choice: paymentChoice,
    add_ons: addOns,
    language,
    message_text: messageText,
    conversation_id: conversationId,
    booking_code: bookingCode,
    addon_request: addonRequest,
    source: 'luna_whatsapp',
    dry_run: true,
    live_send_enabled: false
  }
}];
